curl -X POST 'http://localhost:9200/_aliases?pretty' -d '{
  "actions":[
    {
      "add":{
        "index":"test1",
        "alias":"test1_1",
        "routing":1,
        "filter":{
          "term":{
            "user_id":1
          }
        }
      }
    }
  ]
}'


curl -X GET 'http://localhost:9200/_alias/test1_1?pretty'
